			return false;
		}
		if(sal_estrevista!='' && sal_estrevista < ent_real)
		{
			alert("La Fecha-Hora Salida Entrevista debe ser mayor a Fecha-Hora Entrada Real ");
			return false;
		}
		/*if(sal_real!='' && sal_real < ent_real)
		{
			alert("La Fecha-Hora Salida Real debe ser mayor a Fecha-Hora Entrada Real ");
			return false;
		}  */

		if(Ctrl("arrcheckFILTER").CountRow()==0)
		{
			alert("Seleccionar al menos un Visitante");
			return false;
		}  

		Ctrl("main").DoEvent("SAVE");
	} 
	if(Ctrl('main').GetMode()=='EGRESO_MASIVO')
	{
		 if(Ctrl("arrcheckFILTER").CountRow()==0)
     {
     	alert("Seleccionar al menos un Visitante");
     	return false;
     } 

     Ctrl("main").DoEvent("SAVE");
	}	              

} 
//ONLOAD
function ClearGrdVis_onload()
{   
//alert("onload");       		  
	if(Ctrl('main').GetMode()=='EDIT' || Ctrl('main').GetMode()=='NEW')
	{	
		if(Ctrl("grdDatosVisitantes").RowsCount() != 0) Ctrl("grdDatosVisitantes").DelAllRows();	
	}       

	if(Ctrl('main').GetMode()=='EDITRAPIDO')
	{ 
		//alert("entra");       		  
		REFRESH();   
		var oi_visita = Ctrl('oi_visita').GetXValue();
		var oi_visitante = Ctrl('oi_visitante2').GetXValue();             
		//alert("visita: "+oi_visita);       
		//alert("visitante: "+oi_visitante);       
  	var nSQL = GetProxy().SQLService();  
	  var param =  '<SOURCE oi_visita="'+ oi_visita + '" oi_visitante="'+ oi_visitante + '" />';  
	  /*<ROW l_anteojos="1" l_casco="1" 
	  f_fechahora_sal_es="20181219130000" 
	  d_credencial="0" 
	  f_fechahora_ent="20181219112424" 
	  f_fechahora_en_ent="0" 
	  f_fechahora_sal_en="0" 
	  f_fechahora_sal="0"/> */          
  	var visita = nSQL.GetOBJ(Ctrl("main").getResource("getDatos"), param);
    //alert("d_credencial"+visita.d_credencial);       
    if(visita.d_credencial!='0') {Ctrl('d_credencial').SetXValue(visita.d_credencial);}
    //if(visita.f_fechahora_sal!='0') {Ctrl('f_fechahora_sal').SetXValue(visita.f_fechahora_sal);}
		Ctrl('f_fechahora_sal').SetTypedValue(Now());
		if(visita.f_fechahora_sal_en!='0') {Ctrl('f_fechahora_sal_en').SetXValue(visita.f_fechahora_sal_en);}
		if(visita.f_fechahora_en_ent!='0') {Ctrl('f_fechahora_en_ent').SetXValue(visita.f_fechahora_en_ent);}
		if(visita.f_fechahora_ent!='0') {Ctrl('f_fechahora_ent').SetXValue(visita.f_fechahora_ent);}                                  
		if(visita.f_fechahora_sal_es!='0') {Ctrl('f_fechahora_sal_es').SetXValue(visita.f_fechahora_sal_es);}
		//Ctrl('f_fechahora_sal_es').SetTypedValue(Now());
		if(visita.l_casco!='0') {Ctrl('lcasco').SetXValue(visita.l_casco);}
		if(visita.l_anteojos!='0') {Ctrl('lanteojos').SetXValue(visita.l_anteojos);} 
	}	 

	if(Ctrl('main').GetMode()=='INGRESO_MASIVO')
	{  
		//Seteo fecha-hora actual
		Ctrl('f_fechahora_ent').SetTypedValue(Now());

		var t, ROW, VALUES;
		list2arr = new Array();

		//Valores Iniciales
		for (t=0; t<Ctrl("list2arr").CountRow(); t++)
		{
			ROW=Ctrl("list2arr").GetRow(t); 

			VALUES=ROW.GetAttr("VALUES").split(",");

			for (d=0; d<VALUES.length; d++)
				if (VALUES[d]!="")
					list2arr.push(VALUES[d]);
		}  

	 	//Actualizo la Lista
		//refreshList();
	} 

	if(Ctrl('main').GetMode()=='EGRESO_MASIVO')
	{  
		//Seteo fecha-hora actual
		Ctrl('f_fechahora_sal').SetTypedValue(Now());

		var t, ROW, VALUES;
		list2arr = new Array();

		var auxArr;
		auxArr = exec_qry_egreso(); 
		if (auxArr==null) return;

		list2arr = auxArr;

		refreshList();

	} 
}  

function REFRESH()
{
	Ctrl('d_credencial').SetXValue('');
	Ctrl('f_fechahora_sal').SetXValue('');
	Ctrl('f_fechahora_sal_en').SetXValue('');
	Ctrl('f_fechahora_en_ent').SetXValue('');
	Ctrl('f_fechahora_ent').SetXValue('');
	Ctrl('f_fechahora_sal_es').SetXValue('');
	Ctrl('lcasco').SetXValue('');
	Ctrl('lanteojos').SetXValue(''); 
}    

function load()    { NomadTimeout("internal_load();",100,"Cargando la Lista..."); } 
//function filter()  { NomadTimeout("internal_filter();",100,"Filtrando la Lista..."); }
function loadadd() { NomadTimeout("internal_loadadd();",100,"Agregando en la Lista..."); }        
//function find()    { NomadTimeout("internal_find();",100,"Buscando en la lista..."); }        

function internal_load()
{          

  var auxArr;
	if(Ctrl('main').GetMode()=='EGRESO_MASIVO')
		auxArr = exec_qry_egreso(); 
	else
    auxArr = exec_qry(); 

	if (auxArr==null) return;

	list2arr = auxArr;

	refreshList();
} 


function internal_loadadd()
{
  var auxArr;
  if(Ctrl('main').GetMode()=='EGRESO_MASIVO')
		auxArr = exec_qry_egreso();
	else 
		auxArr = exec_qry();
	if (auxArr==null) return;  

	union(list2arr, auxArr);

	refreshList();
}

//Agrega al Array A los elementos del Array B
function union(arrayA, arrayB)
{                    
	var t;
	var tmp=new Array();

	//Creo la HASH
	for (t=0; t<arrayA.length; t++) 
		tmp["K"+arrayA[t]]=1;

	//Agrego los que no estan	
	for (t=0; t<arrayB.length; t++) 
		if (tmp["K"+arrayB[t]]?false:true)
			arrayA.push(arrayB[t]);
}   

function exec_qry()
{

	var np, nSQL, i;

	np = GetProxy();
	nSQL = np.SQLService(); 	
	//var qry = Ctrl("main").getResource("qry_" + Ctrl("tab_filtro").GetSelectedPanelID());
	var qry = Ctrl("main").getResource("qry_visitante");	
	var qryMembers = qry.split("##");
	var qryMembers = qryMembers[1].split(",");         
	var nmdDATA=new NomadXML("PARAM"); 

	for (i=0; i<qryMembers.length; i++)
	{     
		if(Ctrl(qryMembers[i]) != undefined)
		{
		    if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
			{
				alert("El valor es requerido");
				Ctrl(qryMembers[i]).SetFocus();
				return null;
			}	   
			nmdDATA.SetAttr(qryMembers[i], Ctrl(qryMembers[i]).GetXValue());
		} 	
	} 
  var result = nSQL.GetXML(qry, nmdDATA.ToString());
  var resultArray = XML2array(result);
  return resultArray;
} 

function exec_qry_egreso()
{

	var np, nSQL, i;

	np = GetProxy();
	nSQL = np.SQLService(); 	
	var qry = Ctrl("main").getResource("qry_visitante_egreso");	
	var qryMembers = qry.split("##");
	var qryMembers = qryMembers[1].split(",");       
	var nmdDATA=new NomadXML("PARAM");

	for (i=0; i<qryMembers.length; i++)
	{     
		if(Ctrl(qryMembers[i]) != undefined)
		{        
		  if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
			{
				alert("El valor es requerido");
				Ctrl(qryMembers[i]).SetFocus();
				return null;
			}	  
			nmdDATA.SetAttr(qryMembers[i], Ctrl(qryMembers[i]).GetXValue());
		} 	
	}
  //alert(nmdDATA.ToString());
  var result = nSQL.GetXML(qry, nmdDATA.ToString());
  var resultArray = XML2array(result);
  return resultArray;
}    

//Transaforma un XML(tipo STRING) en ARRAY
function XML2array(xml)
{
	var arr = new Array();                        
	for (var cur=xml.FirstChild(); cur!=null; cur=cur.Next())
		{
		//Obtengo los id de los Visitantes y los guardo en arr
		arr.push(cur.GetAttr("id"));
		}
	return arr;
}  

//Actualiza la lista con el nuevo ARRAY
function refreshList()
{              
 	var page=Ctrl("list2").Page;
	Ctrl("list2").IDs=list2arr;
	Ctrl("list2").ResetSQL();
	Ctrl("list2").GotoPage(page);

	Ctrl("filtrados").SetXValue("Visitantes Filtrados: "+list2arr.length);
	enable_buttons();
}

//Deschequeo TOTAL
function unmarkFILTER()
{
	Ctrl("list2").SetXValue("");
 	Ctrl("arrcheckFILTER").DelAllRow();
	refreshList();
} 

//Elimino iten del FILTRO
function delFILTER()
{                      
	for (var X=0; X<list2arr.length; X++)
	{
		if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",list2arr[X])!=null)
		{                        
			list2arr.splice(X,1);
			X--;
		}
	}

	Ctrl("list2").SetXValue("");
 	Ctrl("arrcheckFILTER").DelAllRow();
	refreshList();
}

//Limpio la Lista del FILTRO
function clearFILTER()
{  
	for (var X=0; X<list2arr.length; X++)
	{
		if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",list2arr[X])==null)
		{                        
			list2arr.splice(X,1);
			X--;
		}
	}

	Ctrl("list2").SetXValue("");
 	Ctrl("arrcheckFILTER").DelAllRow();
	refreshList();
} 

//Function para activar y desactivar Botones
function enable_buttons()
{                   
	CtrlEnabled("list2_Delete", Ctrl("arrcheckFILTER").CountRow()==0?false:true);
	CtrlEnabled("list2_Clear" , true);
}

function checkFILTER()
{    
	var X=Ctrl("list2").GetXValue();
	if (X!="" && Ctrl("list2").LastColumnClick!="SEL")
	{                                                  
		if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",X)==null) Ctrl("arrcheckFILTER").AddRow().SetAttr("ID",X);
		                                                  else Ctrl("arrcheckFILTER").DelRowByAttr("ID",X);    

		Ctrl("list2").SetXValue("");
		refreshList();
	} else           
		enable_buttons();
}

